// resolveProviderID looks up the CLI's active account in the token store and
// returns its UserID (the Google provider ID). The bundle's getThread() path
// is users/<providerId>/threads/<id>; without the providerId we can't read a
// single thread. Honors --account by routing through the same loadConfig +
// ResolveActiveEmail walk that the HTTP client uses.
func resolveProviderID(flags *rootFlags) (string, error) {
	cfg, err := flags.loadConfig()
	if err != nil {
		return "", fmt.Errorf("load config: %w", err)
	}
	email, err := cfg.ResolveActiveEmail()
	if err != nil || email == "" {
		return "", fmt.Errorf("no active account; run 'auth login --disk' or pass --account <email>")
	}
	store := auth.NewStoreAt(cfg.TokenStorePath())
	acct, ok, err := store.Get(email)
	if err != nil {
		return "", fmt.Errorf("load token store: %w", err)
	}
	if !ok {
		return "", fmt.Errorf("account %s not in token store; run 'auth login --disk'", email)
	}
	if acct.UserID == "" {
		return "", fmt.Errorf("account %s has no UserID (google provider id); run 'auth login --disk' to repopulate", email)
	}
	return acct.UserID, nil
}

// activeAccount is the resolved bundle of identity + credentials a Gmail-API
// command needs to construct an internal/gmail Client. resolveActiveAccount
// returns all four together so callers don't repeat the loadConfig + store
// walk in every command.
type activeAccount struct {
	Email       string
	GoogleID    string
	AccessToken string
	Store       *auth.Store
}

// resolveActiveAccount is the multi-field counterpart to resolveProviderID.
// Honors --account exactly the same way (via cfg.ResolveActiveEmail). The
// AccessToken returned is whatever the token store currently holds; gmail
// commands should pass it to gmail.New and let DoWithRefresh refresh it
// when the API returns 401.
func resolveActiveAccount(flags *rootFlags) (*activeAccount, error) {
	cfg, err := flags.loadConfig()
	if err != nil {
		return nil, fmt.Errorf("load config: %w", err)
	}
	email, err := cfg.ResolveActiveEmail()
	if err != nil || email == "" {
		return nil, fmt.Errorf("no active account; run 'auth login --disk' or pass --account <email>")
	}
	store := auth.NewStoreAt(cfg.TokenStorePath())
	acct, ok, err := store.Get(email)
	if err != nil {
		return nil, fmt.Errorf("load token store: %w", err)
	}
	if !ok {
		return nil, fmt.Errorf("account %s not in token store; run 'auth login --disk'", email)
	}
	if acct.UserID == "" {
		return nil, fmt.Errorf("account %s has no UserID (google provider id); run 'auth login --disk' to repopulate", email)
	}
	if acct.AccessToken == "" {
		return nil, fmt.Errorf("account %s has no OAuth access token; run 'auth login --disk' to repopulate", email)
	}
	return &activeAccount{
		Email:       email,
		GoogleID:    acct.UserID,
		AccessToken: acct.AccessToken,
		Store:       store,
	}, nil
}
